CREATE POLICY "Staff roles can update room_housekeeping" ON public.room_housekeeping FOR UPDATE TO authenticated USING (private.has_role(auth.uid(), 'gestor'::app_role) OR private.has_role(auth.uid(), 'recepcao'::app_role) OR private.has_role(auth.uid(), 'camareira'::app_role)) WITH CHECK (private.has_role(auth.uid(), 'gestor'::app_role) OR private.has_role(auth.uid(), 'recepcao'::app_role) OR private.has_role(auth.uid(), 'camareira'::app_role));